class Solution:
    def findSubsequences(self, nums: List[int]) -> List[List[int]]:
        ans = []
        path = []
        def dfs(i):
            if len(path) >= 2: ans.append(path[:])
            used = set()
            for j in range(i, len(nums)):
                if nums[j] in used: continue
                if path and nums[j] < path[-1]: continue
                used.add(nums[j])
                path.append(nums[j])
                dfs(j+1)
                path.pop()
        dfs(0)
        return ans

